<script setup>
import { onMounted, ref } from 'vue'
import { createAdminRelease, deleteAdminRelease, getAdminReleases, updateAdminRelease } from '../services/adminApi'

const entries = ref([]); const form = ref(null); const editingId = ref(null); const error = ref(''); const notice = ref(''); const saving = ref(false)
const empty = () => ({ server: 'SEA', date: new Date().toISOString().slice(0, 10), characterId: '', bannerImage: '', isReturn: false, overrideNameVi: '', overrideNameEn: '', overrideTier: '', overrideFactionVi: '', overrideFactionEn: '', overrideTypeVi: '', overrideTypeEn: '', overrideRoleVi: '', overrideRoleEn: '', sortOrder: 1 })
const load = async () => { try { entries.value = await getAdminReleases() } catch (e) { error.value = e.message } }
const startCreate = () => { editingId.value = null; form.value = empty() }
const startEdit = item => { editingId.value = item.id; form.value = { ...empty(), ...item }; globalThis.scrollTo({ top: 0, behavior: 'smooth' }) }
const save = async () => { saving.value = true; error.value = ''; try { const result = editingId.value ? await updateAdminRelease(editingId.value, form.value) : await createAdminRelease(form.value); notice.value = `Đã lưu mốc #${result.id}.`; form.value = null; editingId.value = null; await load() } catch (e) { error.value = e.message } finally { saving.value = false } }
const remove = async item => { if (!globalThis.confirm(`Xóa mốc ${item.server} ngày ${item.date}?`)) return; try { await deleteAdminRelease(item.id); await load() } catch (e) { error.value = e.message } }
onMounted(load)
</script>
<template><main class="min-h-screen px-4 py-16 sm:px-6 sm:py-24"><div class="mx-auto max-w-7xl"><header class="mb-8 flex items-end justify-between gap-4"><div><p class="text-xs font-black uppercase tracking-[0.24em] text-opm-gold">Quản trị</p><h1 class="mt-2 text-4xl font-black text-white">Lịch ra mắt tướng</h1><p class="mt-2 text-gray-400">Dữ liệu ở đây điều khiển trực tiếp banner CN/SEA trên trang chủ.</p></div><button class="rounded-xl bg-opm-gold px-5 py-3 text-sm font-black text-black" @click="startCreate">+ Thêm mốc</button></header><p v-if="notice" class="mb-4 rounded-xl bg-emerald-500/10 p-3 text-emerald-300">{{ notice }}</p><p v-if="error" class="mb-4 rounded-xl bg-red-500/10 p-3 text-red-300">{{ error }}</p><form v-if="form" class="mb-8 space-y-5 rounded-2xl border border-opm-gold/30 bg-[#0b0d13] p-6" @submit.prevent="save"><div class="grid gap-4 md:grid-cols-2 lg:grid-cols-4"><label class="admin-field"><span>Máy chủ</span><select v-model="form.server"><option>CN</option><option>SEA</option></select></label><label class="admin-field"><span>Ngày</span><input v-model="form.date" type="date" required /></label><label class="admin-field"><span>ID nhân vật</span><input v-model="form.characterId" required placeholder="100313-urplus / unknown" /></label><label class="admin-field"><span>Thứ tự</span><input v-model.number="form.sortOrder" type="number" min="0" max="100" /></label><label class="admin-field md:col-span-2 lg:col-span-3"><span>Ảnh banner</span><input v-model="form.bannerImage" placeholder="/Characters/Full_Background/..." /></label><label class="flex items-center gap-3 rounded-xl border border-white/10 bg-black/20 px-4"><input v-model="form.isReturn" type="checkbox" /><span class="text-sm font-bold text-gray-300">Tướng trở lại</span></label><label class="admin-field"><span>Tên ghi đè VI</span><input v-model="form.overrideNameVi" /></label><label class="admin-field"><span>Tên ghi đè EN</span><input v-model="form.overrideNameEn" /></label><label class="admin-field"><span>Bậc ghi đè</span><input v-model="form.overrideTier" /></label><label class="admin-field"><span>Vai trò VI</span><input v-model="form.overrideRoleVi" /></label><label class="admin-field"><span>Vai trò EN</span><input v-model="form.overrideRoleEn" /></label><label class="admin-field"><span>Phe VI</span><input v-model="form.overrideFactionVi" /></label><label class="admin-field"><span>Phe EN</span><input v-model="form.overrideFactionEn" /></label><label class="admin-field"><span>Hệ VI</span><input v-model="form.overrideTypeVi" /></label><label class="admin-field"><span>Hệ EN</span><input v-model="form.overrideTypeEn" /></label></div><div class="flex justify-end gap-3"><button type="button" class="rounded-xl border border-white/10 px-5 py-2 text-white" @click="form = null">Đóng</button><button :disabled="saving" class="rounded-xl bg-opm-gold px-6 py-2 font-black text-black disabled:opacity-50">{{ saving ? 'Đang lưu…' : 'Lưu mốc lịch' }}</button></div></form><section class="overflow-hidden rounded-2xl border border-white/10 bg-[#0b0d13]"><article v-for="item in entries" :key="item.id" class="flex flex-col gap-4 border-b border-white/5 p-5 last:border-0 sm:flex-row sm:items-center"><img :src="item.bannerImage" :alt="item.characterId" class="h-20 w-28 rounded-xl bg-black/30 object-contain" /><div class="min-w-0 flex-1"><div class="flex flex-wrap items-center gap-2"><strong class="text-white">{{ item.server }} · {{ item.date }}</strong><span class="rounded px-2 py-0.5 text-xs font-black" :class="item.isReturn ? 'bg-red-500/10 text-red-300' : 'bg-opm-gold/10 text-opm-gold'">{{ item.isReturn ? 'TRỞ LẠI' : 'RA MẮT' }}</span></div><p class="mt-1 text-sm text-gray-500">{{ item.characterId }}<span v-if="item.overrideName"> · {{ item.overrideName }}</span></p></div><div class="flex gap-2"><button class="rounded-lg border border-white/10 px-3 py-2 text-sm font-bold text-white" @click="startEdit(item)">Sửa</button><button class="rounded-lg border border-red-500/20 px-3 py-2 text-sm font-bold text-red-300" @click="remove(item)">Xóa</button></div></article></section></div></main></template>
<style scoped>.admin-field span{@apply mb-2 block text-[11px] font-bold uppercase tracking-wider text-gray-400}.admin-field input,.admin-field select{@apply w-full rounded-xl border border-white/10 bg-black/30 px-3 py-2.5 text-sm text-white outline-none transition focus:border-opm-gold}</style>
